/**
 * Match order items with template and fill quantities
 */
function matchAndFillQuantities(processedSheet, items) {
  try {
    const sheet = processedSheet.getSheets()[0];
    const templateData = sheet.getDataRange().getValues();

    console.log('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━');
    console.log('MATCHING DEBUG INFO');
    console.log('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━');
    console.log('Template has', templateData.length, 'rows');

    // Column indices (0-based)
    const styleCol = 7;    // H - Style/Item Name (column H = index 7)
    const colorCol = 5;    // F - Color (column F = index 5)
    const sizeCol = 10;    // K - Size (column K = index 10)
    const qtyCol = 14;     // O - Order Qty (column O = index 14)

    console.log('Column mapping: Style=H(7), Color=F(5), Size=K(10), Qty=O(14)');

    // Consolidate orders (combine same item/color/size)
    const consolidated = {};
    for (const item of items) {
      // Normalize order item values - remove leading/trailing spaces and underscores
      const normalizedItemName = String(item.itemName || '').trim().replace(/^[_\s]+|[_\s]+$/g, '');
      const normalizedColor = String(item.color || '').trim().replace(/^[_\s]+|[_\s]+$/g, '');
      const normalizedSize = String(item.size || '').trim().replace(/^[_\s]+|[_\s]+$/g, '');

      const key = `${normalizedItemName}|${normalizedColor}|${normalizedSize}`.toLowerCase();
      if (consolidated[key]) {
        consolidated[key].quantity += item.quantity;
      } else {
        consolidated[key] = {
          itemName: normalizedItemName,
          color: normalizedColor,
          size: normalizedSize,
          quantity: item.quantity
        };
      }
    }

    console.log('Consolidated items:', Object.keys(consolidated).length);
    console.log('Items to match:');
    for (const key in consolidated) {
      const item = consolidated[key];
      console.log(`  - ${item.itemName} | ${item.color} | ${item.size} | Qty: ${item.quantity}`);
    }
    console.log('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━');

    let matched = 0;
    const unmatched = [];

    // Match with template
    for (const key in consolidated) {
      const orderItem = consolidated[key];
      let found = false;

      console.log(`\nSearching for: ${orderItem.itemName} | ${orderItem.color} | ${orderItem.size}`);

      for (let j = 0; j < templateData.length; j++) {
        const tRow = templateData[j];

        // Skip invalid rows
        if (!tRow || tRow.length <= Math.max(styleCol, colorCol, sizeCol, qtyCol)) {
          continue;
        }

        // Get template values and normalize - remove leading/trailing spaces and underscores
        const tStyle = String(tRow[styleCol] || '').trim().replace(/^[_\s]+|[_\s]+$/g, '').toLowerCase();
        const tColor = String(tRow[colorCol] || '').trim().replace(/^[_\s]+|[_\s]+$/g, '').toLowerCase();
        const tSize = String(tRow[sizeCol] || '').trim().replace(/^[_\s]+|[_\s]+$/g, '').toLowerCase();

        // Debug logging - show first 10 rows for each search
        if (j < 10) {
          console.log(`  Row ${j + 1}: [${tStyle}] | [${tColor}] | [${tSize}]`);
        }

        // Match item
        if (tStyle === orderItem.itemName.toLowerCase() && 
            tColor === orderItem.color.toLowerCase() && 
            tSize === orderItem.size.toLowerCase()) {

          // Update quantity
          const currentQty = Number(tRow[qtyCol]) || 0;
          const newQty = currentQty + orderItem.quantity;

          sheet.getRange(j + 1, qtyCol + 1).setValue(newQty);

          console.log(`✓✓✓ MATCH FOUND at Row ${j + 1}: ${orderItem.itemName} | ${orderItem.color} | ${orderItem.size} → Qty: ${newQty}`);
          matched++;
          found = true;
          break;
        }
      }

      // Track unmatched items
      if (!found) {
        const unmatchedLabel = `${orderItem.itemName} | ${orderItem.color} | ${orderItem.size} (Qty: ${orderItem.quantity})`;
        unmatched.push(unmatchedLabel);
        console.log('✗✗✗ NO MATCH FOUND:', unmatchedLabel);
      }
    }

    // Save changes
    SpreadsheetApp.flush();

    console.log('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━');
    console.log('MATCHING SUMMARY');
    console.log('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━');
    console.log('Matched:', matched);
    console.log('Unmatched:', unmatched.length);
    if (unmatched.length > 0) {
      console.log('Unmatched items:');
      unmatched.forEach(item => console.log('  -', item));

      // Collect debug info for error email
      const templateSample = [];
      for (let i = 0; i < Math.min(10, templateData.length); i++) {
        const row = templateData[i];
        if (row && row.length > Math.max(styleCol, colorCol, sizeCol)) {
          const style = String(row[styleCol] || '').trim().replace(/^[_\s]+|[_\s]+$/g, '');
          const color = String(row[colorCol] || '').trim().replace(/^[_\s]+|[_\s]+$/g, '');
          const size = String(row[sizeCol] || '').trim().replace(/^[_\s]+|[_\s]+$/g, '');
          if (style || color || size) {
            templateSample.push({
              rowNum: i + 1,
              style: style,
              color: color,
              size: size
            });
          }
        }
      }

      // Send detailed error email with unmatched items
      const debugInfo = {
        items: Object.values(consolidated),
        templateSample: templateSample,
        unmatched: unmatched
      };

      sendErrorEmail(
        `${unmatched.length} item(s) could not be matched in template`,
        debugInfo
      );
    }
    console.log('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━');

    return { matched, unmatched };
  } catch (err) {
    throw new Error('Failed to match quantities: ' + err.message);
  }
}

/**
 * Apply filter to column O to hide blank cells
 */
function applyFilterToSheet(spreadsheet) {
  try {
    const sheet = spreadsheet.getSheets()[0];
    const lastRow = sheet.getLastRow();
    const lastCol = sheet.getLastColumn();

    if (lastRow < 1 || lastCol < 15) {
      console.log('Sheet too small to apply filter');
      return;
    }

    // Remove existing filters first
    const existingFilter = sheet.getFilter();
    if (existingFilter) {
      existingFilter.remove();
      console.log('Removed existing filter');
    }

    // Create new filter on entire data range
    const range = sheet.getRange(1, 1, lastRow, lastCol);
    const filter = range.createFilter();
    console.log('✅ Filter created on range:', range.getA1Notation());

    // Column O is the 15th column (index 15)
    // Set criteria to hide blank cells
    const criteria = SpreadsheetApp.newFilterCriteria()
      .whenCellNotEmpty()
      .build();

    filter.setColumnFilterCriteria(15, criteria);
